pauli_stabilizers = [stim.PauliString(s) for s in stabilizers]

tableau = stim.Tableau.from_stabilizers(pauli_stabilizers, allow_redundant=True, allow_underconstrained=True)
circuit = tableau.to_circuit(method="graph_state")

# Replace RX with H
# Get the circuit as string
c_str = str(circuit)
lines = c_str.split('\n')
new_lines = []
for line in lines:
    if line.startswith("RX "):
        new_lines.append(line.replace("RX ", "H "))
    elif line.startswith("TICK"):
        pass # Remove ticks
    else:
        new_lines.append(line)

final_circuit_str = '\n'.join(new_lines)
with open("candidate.stim", "w") as f:
    f.write(final_circuit_str)
